import { useState } from "react";
import { createPortal } from "react-dom";
import { logo } from "../../assets/images";
import styles from "./layout.module.scss";

export default function Header() {
  const headerRoot = document.getElementById("header");
  if (!headerRoot) return null;

  const [hoverKO, setHoverKO] = useState(false);
  const [hoverEN, setHoverEN] = useState(false);

  return createPortal(
    <div className={styles.headerInner}>
      <ul>
        <li
          onMouseEnter={() => setHoverKO(true)}
          onMouseLeave={() => setHoverKO(false)}
          className={hoverKO ? "hoverEffect" : ""}
        >
          KO
        </li>
        <li>|</li>
        <li
          onMouseEnter={() => setHoverEN(true)}
          onMouseLeave={() => setHoverEN(false)}
          className={hoverEN ? "hoverEffect" : ""}
        >
          EN
        </li>
      </ul>

      <a href="/">
        <img src={logo} alt="Logo" />
      </a>

      <nav>
        <button type="button">
          <span></span>
          <span></span>
          <span></span>
        </button>
        <ol>
          <li>HOME</li>
          <li>PROFILE</li>
          <li>PROJECTS</li>
          <li>CONTACT</li>
        </ol>
      </nav>
    </div>,
    headerRoot
  );
}
